import React from 'react';
import './TopUsers.css';

const TopUsers = () => {
  const users = [
    { id: 1, name: 'darlingohioo', level: 9999, rank: 1 },
    { id: 2, name: 'mangalover', level: 8500, rank: 2 },
    { id: 3, name: 'animefan', level: 7200, rank: 3 }
  ];

  const rankIcon = (rank) => {
    if (rank === 1) return 'fa-crown';
    if (rank === 2) return 'fa-medal';
    return 'fa-award';
  };

  return (
    <div className="top-users-card">
      <h3><i className="fas fa-trophy"></i> Top users</h3>
      <div className="users-grid">
        {users.map((user) => (
          <div key={user.id} className="user-card" data-rank={user.rank}>
            <div className="user-avatar">
              <i className={`fas ${rankIcon(user.rank)}`}></i>
              <span className="user-rank">{user.rank}</span>
            </div>
            <div className="user-info">
              <div className="username">{user.name}</div>
              <div className="user-score"><i className="fas fa-star"></i>{user.level}</div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TopUsers;
